#!/usr/bin/env node
'use strict';

// Builds encrypted question bundles, one per role.
//
//   PT_OWNER_PASS=...  PT_FRIEND_PASS=...  node tools/build-bundles.js
//
// Source : ../questions.json  (the existing plaintext DB)
// Outputs: ../questions.owner.enc.js   — full DB, encrypted with owner pass
//          ../questions.friend.enc.js  — only BOSA_SJT_BA_CRIT, encrypted with friend pass
//
// Each output is a small JS file that assigns base64'd {salt, iv, ct, iter}
// to window.__BUNDLES.<role>.  The browser derives the key with PBKDF2 from
// the typed password and decrypts via WebCrypto AES-GCM.
//
// Wrong password ⇒ AES-GCM auth failure ⇒ "Wrong password".

const fs = require('fs');
const path = require('path');
const crypto = require('crypto');

const ROOT = path.resolve(__dirname, '..');
const SRC  = path.join(ROOT, 'questions.json');

const ITER = 200_000;

const ROLES = {
  owner:  { envVar: 'PT_OWNER_PASS',  out: 'questions.owner.enc.js' },
  friend: { envVar: 'PT_FRIEND_PASS', out: 'questions.friend.enc.js',
            sources: ['BOSA_SJT_BA_CRIT'] },
};

function encryptJson(obj, password) {
  const salt = crypto.randomBytes(16);
  const iv   = crypto.randomBytes(12);
  const key  = crypto.pbkdf2Sync(password, salt, ITER, 32, 'sha256');
  const cipher = crypto.createCipheriv('aes-256-gcm', key, iv);
  const pt = Buffer.from(JSON.stringify(obj), 'utf8');
  const body = Buffer.concat([cipher.update(pt), cipher.final()]);
  const tag  = cipher.getAuthTag();
  // WebCrypto AES-GCM wants ciphertext || tag concatenated.
  const ct = Buffer.concat([body, tag]);
  return {
    salt: salt.toString('base64'),
    iv:   iv.toString('base64'),
    ct:   ct.toString('base64'),
    iter: ITER,
  };
}

function buildRole(role, db) {
  const cfg = ROLES[role];
  const password = process.env[cfg.envVar];
  if (!password) {
    console.error(`✗ ${role}: env var ${cfg.envVar} not set — skipping`);
    return false;
  }
  let payload = db;
  if (cfg.sources) {
    const allow = new Set(cfg.sources);
    payload = {
      ...db,
      sources: db.sources.filter(s => allow.has(s)),
      questions: db.questions.filter(q => allow.has(q.source)),
    };
  }
  const enc = encryptJson(payload, password);
  const js =
    `// Auto-generated by tools/build-bundles.js — do not edit by hand.\n` +
    `window.__BUNDLES = window.__BUNDLES || {};\n` +
    `window.__BUNDLES.${role} = ${JSON.stringify(enc)};\n`;
  const outPath = path.join(ROOT, cfg.out);
  fs.writeFileSync(outPath, js);
  console.log(`✓ ${cfg.out}  (${payload.questions.length} questions, ${(js.length/1024).toFixed(0)} KB)`);
  return true;
}

const db = JSON.parse(fs.readFileSync(SRC, 'utf8'));
let any = false;
for (const role of Object.keys(ROLES)) {
  if (buildRole(role, db)) any = true;
}
if (!any) {
  console.error('\nNo bundles built. Set PT_OWNER_PASS and/or PT_FRIEND_PASS, e.g.:');
  console.error('  PT_OWNER_PASS=your-owner-pw PT_FRIEND_PASS=AliciaCRIT node tools/build-bundles.js');
  process.exit(1);
}
